package jsonpath

import (
	"encoding/json"
	"testing"
)

func parse(s string) interface{} {
	var v interface{}
	json.Unmarshal([]byte(s), &v)
	return v
}

func TestDotNotation(t *testing.T) {
	data := parse(`{"store":{"name":"Books R Us"}}`)
	result, err := Query(data, "$.store.name")
	if err != nil {
		t.Fatal(err)
	}
	if result[0] != "Books R Us" {
		t.Errorf("expected 'Books R Us', got %v", result[0])
	}
}

func TestArrayIndex(t *testing.T) {
	data := parse(`{"items":["a","b","c"]}`)
	result, err := Query(data, "$.items[1]")
	if err != nil {
		t.Fatal(err)
	}
	if result[0] != "b" {
		t.Errorf("expected 'b', got %v", result[0])
	}
}

func TestDeepSearch(t *testing.T) {
	data := parse(`{"a":{"title":"X"},"b":{"c":{"title":"Y"}}}`)
	result, err := Query(data, "$..title")
	if err != nil {
		t.Fatal(err)
	}
	if len(result) != 2 {
		t.Fatalf("expected 2 results, got %d", len(result))
	}
}

func TestNotFound(t *testing.T) {
	data := parse(`{"a":1}`)
	result, err := Query(data, "$.b")
	if err != nil {
		t.Fatal(err)
	}
	if len(result) != 0 {
		t.Errorf("expected empty result, got %v", result)
	}
}

package jsonpath

import (
	"fmt"
	"strconv"
	"strings"
)

func Query(data interface{}, path string) ([]interface{}, error) {
	if !strings.HasPrefix(path, "$") {
		return nil, fmt.Errorf("path must start with $")
	}

	path = strings.TrimPrefix(path, "$")
	if path == "" {
		return []interface{}{data}, nil
	}

	// Handle deep search
	if strings.HasPrefix(path, "..") {
		key := strings.TrimPrefix(path, "..")
		var results []interface{}
		deepSearch(data, key, &results)
		return results, nil
	}

	// Parse segments
	path = strings.TrimPrefix(path, ".")
	segments := parsePath(path)

	current := []interface{}{data}
	for _, seg := range segments {
		var next []interface{}
		for _, item := range current {
			resolved := resolve(item, seg)
			if resolved != nil {
				next = append(next, resolved)
			}
		}
		current = next
	}
	return current, nil
}

func parsePath(path string) []string {
	var segments []string
	for path != "" {
		if strings.HasPrefix(path, "[") {
			end := strings.Index(path, "]")
			if end == -1 {
				break
			}
			segments = append(segments, path[:end+1])
			path = path[end+1:]
			path = strings.TrimPrefix(path, ".")
		} else {
			dot := strings.Index(path, ".")
			bracket := strings.Index(path, "[")
			var end int
			switch {
			case dot == -1 && bracket == -1:
				end = len(path)
			case dot == -1:
				end = bracket
			case bracket == -1:
				end = dot
			default:
				end = dot
				if bracket < dot {
					end = bracket
				}
			}
			segments = append(segments, path[:end])
			path = path[end:]
			path = strings.TrimPrefix(path, ".")
		}
	}
	return segments
}

func resolve(data interface{}, segment string) interface{} {
	if strings.HasPrefix(segment, "[") && strings.HasSuffix(segment, "]") {
		idxStr := segment[1 : len(segment)-1]
		idx, err := strconv.Atoi(idxStr)
		if err != nil {
			return nil
		}
		if arr, ok := data.([]interface{}); ok && idx >= 0 && idx < len(arr) {
			return arr[idx]
		}
		return nil
	}

	if m, ok := data.(map[string]interface{}); ok {
		if val, exists := m[segment]; exists {
			return val
		}
	}
	return nil
}

func deepSearch(data interface{}, key string, results *[]interface{}) {
	switch v := data.(type) {
	case map[string]interface{}:
		if val, exists := v[key]; exists {
			*results = append(*results, val)
		}
		for _, val := range v {
			deepSearch(val, key, results)
		}
	case []interface{}:
		for _, item := range v {
			deepSearch(item, key, results)
		}
	}
}
